export const ListLeadsQueryParams = zod.object({
  page: zod.coerce.number().default(listLeadsQueryPageDefault),
  limit: zod.coerce.number().default(listLeadsQueryLimitDefault),
  companyId: zod.coerce.number().nullish(),
  search: zod.coerce.string().nullish(),
});

export const listLeadsResponseLeadsItemStatusDefault = `new`;
export const listLeadsResponseLeadsItemCompanyCountryDefault = `Saudi Arabia`;

export const ListLeadsResponse = zod.object({
  leads: zod.array(
    zod.object({
      id: zod.number(),
      companyId: zod.number().nullish(),
      firstName: zod.string().nullish(),
      lastName: zod.string().nullish(),
      firstNameAr: zod.string().nullish(),
      lastNameAr: zod.string().nullish(),
      title: zod.string().nullish(),
      titleAr: zod.string().nullish(),
      email: zod.string().nullish(),
      phone: zod.string().nullish(),
      linkedinUrl: zod.string().nullish(),
      twitterUrl: zod.string().nullish(),
      department: zod.string().nullish(),
      seniority: zod.string().nullish(),
      notes: zod.string().nullish(),
      status: zod
        .enum(["new", "contacted", "qualified", "converted", "disqualified"])
        .default(listLeadsResponseLeadsItemStatusDefault),
      company: zod
        .object({
          id: zod.number(),
          nameAr: zod.string().nullish(),
          nameEn: zod.string().nullish(),
          industry: zod.string().nullish(),
          industryAr: zod.string().nullish(),
          city: zod.string().nullish(),
          region: zod.string().nullish(),
          country: zod
            .string()
            .default(listLeadsResponseLeadsItemCompanyCountryDefault),
          website: zod.string().nullish(),
          phone: zod.string().nullish(),
          email: zod.string().nullish(),
          description: zod.string().nullish(),
          descriptionAr: zod.string().nullish(),
          employeeCount: zod.number().nullish(),
          revenue: zod.string().nullish(),
          foundingYear: zod.number().nullish(),
          crNumber: zod.string().nullish(),
          capitalAmount: zod.string().nullish(),
          entityType: zod.string().nullish(),
          companyType: zod.string().nullish(),
          ownerName: zod.string().nullish(),
          ownerNameAr: zod.string().nullish(),
          ownerTitle: zod.string().nullish(),
          ownerPhone: zod.string().nullish(),
          ownerEmail: zod.string().nullish(),
          ownerLinkedin: zod.string().nullish(),
          estimatedWealth: zod.string().nullish(),
          shareholders: zod
            .string()
            .nullish()
            .describe("JSON array of shareholders with ownership percentage"),
          keyExecutives: zod
            .string()
            .nullish()
            .describe("JSON array of key executives"),
          marketPositioning: zod.string().nullish(),
          recentNews: zod
            .string()
            .nullish()
            .describe("JSON array of recent news items"),
          linkedinUrl: zod.string().nullish(),
          twitterUrl: zod.string().nullish(),
          enrichmentScore: zod
            .number()
            .nullish()
            .describe("0-100 enrichment completeness score"),
          enrichmentStatus: zod
            .union([
              zod.literal("enriched"),
              zod.literal("partial"),
              zod.literal("pending"),
              zod.literal(null),
            ])
            .nullish(),
          dataSource: zod.string().nullish(),
          tags: zod.string().nullish().describe("Comma-separated tags"),
          createdAt: zod.date(),
          updatedAt: zod.date(),
        })
        .optional(),
      createdAt: zod.date(),
      updatedAt: zod.date(),
    }),
  ),
  total: zod.number(),
  page: zod.number(),
  limit: zod.number(),
  totalPages: zod.number(),
});

